def gen(rng, size):
    n = rng.randint(1, max(1, min(300, size)))
    arr = sorted(rng.randint(-20, 20) for _ in range(n))
    p = rng.randint(0, n - 1)
    rotated = arr[p:] + arr[:p]
    if rng.random() < 0.6 and rotated:
        target = rng.choice(rotated)
    else:
        target = rng.randint(-25, 25)
    return [rotated, target]

